19	
20	library ieee;
21	use ieee.std_logic_1164.all;
22	use ieee.std_logic_arith.all;
23	use ieee.std_logic_unsigned.all;
24	
25	library surf;
26	use surf.StdRtlPkg.all;
27	use surf.AxiStreamPkg.all;
28	use surf.SsiPkg.all;
29	
30	entity SsiObFrameFilter is
31	   generic (
32	      TPD_G          : time    := 1 ns;
33	      RST_POLARITY_G : sl      := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
34	      RST_ASYNC_G    : boolean := false;
35	      VALID_THOLD_G  : natural := 1;
36	      PIPE_STAGES_G  : natural := 1;
37	      AXIS_CONFIG_G  : AxiStreamConfigType);
38	   port (
39	      -- Slave Port (AXIS FIFO Read Interface)
40	      sAxisMaster    : in  AxiStreamMasterType;
41	      sTLastTUser    : in  slv(7 downto 0);
42	      sAxisSlave     : out AxiStreamSlaveType;
43	      -- Master Port
44	      mAxisMaster    : out AxiStreamMasterType;
45	      mAxisSlave     : in  AxiStreamSlaveType;
46	      mAxisDropWord  : out sl;          -- Word dropped status output
47	      mAxisDropFrame : out sl;          -- Frame dropped status output
48	      -- Clock and Reset
49	      axisClk        : in  sl;
50	      axisRst        : in  sl);
51	end SsiObFrameFilter;
52	
53	architecture rtl of SsiObFrameFilter is
54	
55	   type StateType is (
56	      IDLE_S,
57	      BLOWOFF_S,
58	      MOVE_S);
59	
60	   type RegType is record
61	      sof          : sl;
62	      eofe         : sl;
63	      wordDropped  : sl;
64	      frameDropped : sl;
65	      tDest        : slv(7 downto 0);
66	      master       : AxiStreamMasterType;
67	      slave        : AxiStreamSlaveType;
68	      state        : StateType;
69	   end record RegType;
70	
71	   constant REG_INIT_C : RegType := (
72	      sof          => '0',
73	      eofe         => '0',
74	      wordDropped  => '0',
75	      frameDropped => '0',
76	      tDest        => x"00",
77	      master       => AXI_STREAM_MASTER_INIT_C,
78	      slave        => AXI_STREAM_SLAVE_INIT_C,
79	      state        => IDLE_S);
80	
81	   signal r   : RegType := REG_INIT_C;
82	   signal rin : RegType;
83	
84	   signal axisMaster : AxiStreamMasterType;
85	   signal axisSlave  : AxiStreamSlaveType;
86	
87	begin
88	
89	   assert (AXIS_CONFIG_G.TUSER_BITS_C >= 2)
90	      report "SsiObFrameFilter:  AXIS_CONFIG_G.TUSER_BITS_C must be >= 2" severity failure;
91	
92	   comb : process (axisRst, axisSlave, r, sAxisMaster, sTLastTUser) is
93	      variable v : RegType;
94	   begin
95	      -- Latch the current value
96	      v := r;
97	
98	      -- Reset strobe Signals
99	      v.wordDropped  := '0';
100	      v.frameDropped := '0';
101	
102	      -- Flow Control Signals
103	      v.slave := AXI_STREAM_SLAVE_INIT_C;
104	      if (axisSlave.tReady = '1') then
105	         v.master.tValid := '0';
106	      end if;
107	
108	      -- Get the SOF status
109	      v.sof := ssiGetUserSof(AXIS_CONFIG_G, sAxisMaster);
110	
111	      -- Check for FIFO caching
112	      if (VALID_THOLD_G = 0) then
113	         -- Get the EOFE status
114	         v.eofe := sTLastTUser(SSI_EOFE_C);
115	      else
116	         -- Reset the flag
117	         v.eofe := '0';
118	      end if;
119	
120	      -- State Machine
121	      case (r.state) is
122	         ----------------------------------------------------------------------
123	         when IDLE_S =>
124	            -- Check if ready to move data
125	            if (v.master.tValid = '0') and (sAxisMaster.tValid = '1') then
126	
127	               -- Accept the data
128	               v.slave.tReady := '1';
129	
130	               -- Check of no-SOF or  EOFE detected in the FIFO
131	               if (v.sof = '0') or (v.eofe = '1') then
132	
133	                  -- Strobe the error flags
134	                  v.wordDropped  := sAxisMaster.tValid;
135	                  v.frameDropped := sAxisMaster.tLast;
136	
137	                  -- Check for non-EOF
138	                  if (sAxisMaster.tLast = '0') then
139	                     -- Next state
140	                     v.state := BLOWOFF_S;
141	                  end if;
142	
143	               -- Else normal framing detected
144	               else
145	
146	                  -- Move the data bus
147	                  v.master := sAxisMaster;
148	
149	                  -- Latch tDest
150	                  v.tDest := sAxisMaster.tDest;
151	
152	                  -- Check for no EOF
153	                  if (sAxisMaster.tLast = '0') then
154	                     -- Next state
155	                     v.state := MOVE_S;
156	                  end if;
157	
158	               end if;
159	            end if;
160	         ----------------------------------------------------------------------
161	         when BLOWOFF_S =>
162	            -- Blow-off the data
163	            v.slave.tReady := '1';
164	
165	            -- Strobe the error flags
166	            v.wordDropped  := sAxisMaster.tValid;
167	            v.frameDropped := sAxisMaster.tLast;
168	
169	            -- Check for EOF
170	            if (sAxisMaster.tValid = '1') and (sAxisMaster.tLast = '1') then
171	               -- Next state
172	               v.state := IDLE_S;
173	            end if;
174	         ----------------------------------------------------------------------
175	         when MOVE_S =>
176	            -- Check if ready to move data
177	            if (v.master.tValid = '0') and (sAxisMaster.tValid = '1') then
178	
179	               -- Accept the data
180	               v.slave.tReady := '1';
181	
182	               -- Move the data bus
183	               v.master := sAxisMaster;
184	
185	               -- Check for EOF
186	               if (sAxisMaster.tLast = '1') then
187	                  -- Next state
188	                  v.state := IDLE_S;
189	               end if;
190	
191	               -- Check for SSI framing errors (repeated SOF or interleaved frame)
192	               if (v.sof = '1') or (r.tDest /= sAxisMaster.tDest) then
193	
194	                  -- Set the EOF flag
195	                  v.master.tLast := '1';
196	
197	                  -- Set the EOFE flag
198	                  ssiSetUserEofe(AXIS_CONFIG_G, v.master, '1');
199	
200	                  -- Override SOF flag
201	                  ssiSetUserSof(AXIS_CONFIG_G, v.master, '0');
202	
203	                  -- Strobe the error flags
204	                  v.wordDropped  := sAxisMaster.tValid;
205	                  v.frameDropped := sAxisMaster.tLast;
206	
207	                  -- Next state
208	                  v.state := IDLE_S;
209	
210	               end if;
211	
212	            end if;
213	      ----------------------------------------------------------------------
214	      end case;
215	
216	      -- Slave Outputs
217	      sAxisSlave <= v.slave;
218	
219	      -- Master Outputs
220	      axisMaster     <= r.master;
221	      mAxisDropWord  <= r.wordDropped;
222	      mAxisDropFrame <= r.frameDropped;
223	
224	      -- Synchronous Reset
225	      if (RST_ASYNC_G = false and axisRst = RST_POLARITY_G) then
226	         v := REG_INIT_C;
227	      end if;
228	
229	      -- Register the variable for next clock cycle
230	      rin <= v;
231	
232	   end process comb;
233	
234	   seq : process (axisClk, axisRst) is
235	   begin
236	      if (RST_ASYNC_G) and (axisRst = RST_POLARITY_G) then
237	         r <= REG_INIT_C after TPD_G;
238	      elsif rising_edge(axisClk) then
239	         r <= rin after TPD_G;
240	      end if;
241	   end process seq;
242	
243	   U_Pipe : entity surf.AxiStreamPipeline
244	      generic map (
245	         TPD_G          => TPD_G,
246	         RST_POLARITY_G => RST_POLARITY_G,
247	         RST_ASYNC_G    => RST_ASYNC_G,
248	         PIPE_STAGES_G  => PIPE_STAGES_G)
249	      port map (
250	         -- Clock and Reset
251	         axisClk     => axisClk,
252	         axisRst     => axisRst,
253	         -- Slave Port
254	         sAxisMaster => axisMaster,
255	         sAxisSlave  => axisSlave,
256	         -- Master Port
257	         mAxisMaster => mAxisMaster,
258	         mAxisSlave  => mAxisSlave);
259	
260	end rtl;
